// Handles both Calendly v2 (invitee.created / invitee.canceled) and generic
// booking webhook formats. Sets is_valid_booking = true only for new-booking
// events — guards against cancellation and reschedule events on the same endpoint.

const raw  = $input.first().json;
const body = raw.body || raw; // n8n webhook configs may nest the payload inside .body

let normalized;

// Calendly v2 real webhook: invitee data sits directly on body.payload (not body.payload.invitee).
// The scheduled event details are at body.payload.scheduled_event.
if (body.payload && body.payload.scheduled_event) {
  // ── Calendly v2 shape ──────────────────────────────────────────────────────
  const p   = body.payload;
  const evt = p.scheduled_event || {};

  // Phone: prefer text_reminder_number; fall back to a custom Q&A 'phone' field.
  // text_reminder_number is opt-in in Calendly — it may be absent or null.
  let phone = p.text_reminder_number || '';
  if (!phone && Array.isArray(p.questions_and_answers)) {
    const phoneQ = p.questions_and_answers.find(
      q => /phone/i.test(q.question) && q.answer
    );
    if (phoneQ) phone = phoneQ.answer;
  }

  normalized = {
    contact_name:     p.name || `${p.first_name || ''} ${p.last_name || ''}`.trim(),
    contact_email:    p.email || '',
    contact_phone:    phone,
    appointment_time: evt.start_time || '',
    consult_type:     evt.name || 'consultation',
    reschedule_url:   p.reschedule_url || '',
    booking_event:    body.event || 'invitee.created',
    source:           'calendly',
    is_valid_booking: body.event === 'invitee.created'
                      && !!(p.email || phone)
                      && !!evt.start_time,
  };
} else {
  // ── Generic booking webhook (Acuity, Cal.com, Fluent Forms, PM systems, etc.) ─
  const evtType = body.event_type || '';
  normalized = {
    contact_name:     body.contact_name || body.name || '',
    contact_email:    body.contact_email || body.email || '',
    contact_phone:    body.contact_phone || body.phone || '',
    appointment_time: body.appointment_time || body.start_time || '',
    consult_type:     body.consult_type || body.appointment_type || 'consultation',
    reschedule_url:   body.reschedule_url || '',
    booking_event:    evtType,
    source:           'generic',
    // Reject explicit cancel/reschedule events; require contact info and a time
    is_valid_booking: !/cancel|reschedul/i.test(evtType)
                      && !!(body.contact_email || body.email
                            || body.contact_phone || body.phone)
                      && !!(body.appointment_time || body.start_time),
  };
}

return [{ json: { ...normalized, timestamp: new Date().toISOString() } }];

// Reads firm details from n8n Variables (project → Variables tab).
// Set: FIRM_NAME, FIRM_EMAIL, FIRM_FROM_EMAIL, FIRM_TWILIO_NUMBER, FIRM_BOOKING_URL, FIRM_TIMEZONE
const FIRM_NAME          = $vars.FIRM_NAME;
const FIRM_EMAIL         = $vars.FIRM_EMAIL;            // where firm copies of reminders go
const FROM_EMAIL         = $vars.FIRM_FROM_EMAIL;       // the address reminder emails come from (must be authorised by your SMTP account)
const FIRM_TWILIO_NUMBER = $vars.FIRM_TWILIO_NUMBER;    // your Twilio SMS number (E.164)
const BOOKING_URL        = $vars.FIRM_BOOKING_URL;      // fallback if no per-booking reschedule URL
const TIMEZONE           = $vars.FIRM_TIMEZONE;         // e.g. 'America/Chicago', 'America/Los_Angeles'

const item    = $input.first().json;
const now     = new Date();
const aptTime = new Date(item.appointment_time);

// Calculate ISO timestamps for each Wait node.
// If a booking arrives less than 24 h before the appointment, the 24 h reminder
// fires almost immediately (floors to now + 90 s). Same for the 1 h reminder.
const MIN_WAIT = 90_000; // 90-second floor so Wait never fires before prior steps finish
const MS_24H   = 24 * 60 * 60 * 1000;
const MS_1H    =      60 * 60 * 1000;
const MS_15M   =      15 * 60 * 1000;

const reminder_24h_at = new Date(
  Math.max(aptTime.getTime() - MS_24H, now.getTime() + MIN_WAIT)
).toISOString();
const reminder_1h_at = new Date(
  Math.max(aptTime.getTime() - MS_1H, now.getTime() + MIN_WAIT * 2)
).toISOString();
const noshow_check_at = new Date(aptTime.getTime() + MS_15M).toISOString();

const aptDateStr = aptTime.toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', timeZone: TIMEZONE,
});
const aptTimeStr = aptTime.toLocaleTimeString('en-US', {
  hour: 'numeric', minute: '2-digit', timeZoneName: 'short', timeZone: TIMEZONE,
});

const rescheduleUrl = item.reschedule_url || BOOKING_URL;
const firstName     = (item.contact_name || '').split(' ')[0] || '';
const greeting      = firstName ? `Hi ${firstName}` : 'Hello';
const consultType   = item.consult_type || 'consultation';

// Pre-build all four SMS bodies in one place — all include TCPA opt-out instruction.
const confirmSms  = `${greeting}, your ${consultType} with ${FIRM_NAME} is confirmed for ${aptDateStr} at ${aptTimeStr}. We look forward to speaking with you! Reply STOP to opt out.`;
const remind24Sms = `${greeting}, a friendly reminder: your ${consultType} with ${FIRM_NAME} is tomorrow at ${aptTimeStr}. See you then! Reply STOP to opt out.`;
const remind1hSms = `${greeting}, your ${consultType} with ${FIRM_NAME} starts in 1 hour at ${aptTimeStr}. Can't make it? Reschedule: ${rescheduleUrl} — Reply STOP to opt out.`;
const noshowSms   = `${greeting}, we had your ${consultType} scheduled today at ${aptTimeStr} with ${FIRM_NAME}. If anything came up, no worries — reschedule here: ${rescheduleUrl} — Reply STOP to opt out.`;

return [{ json: {
  ...item,
  firm_name:            FIRM_NAME,
  firm_email:           FIRM_EMAIL,
  from_email:           FROM_EMAIL,
  firm_twilio_number:   FIRM_TWILIO_NUMBER,
  booking_url:          BOOKING_URL,
  reschedule_url_final: rescheduleUrl,
  apt_date_str:         aptDateStr,
  apt_time_str:         aptTimeStr,
  greeting,
  first_name:           firstName,
  consult_type:         consultType,
  reminder_24h_at,
  reminder_1h_at,
  noshow_check_at,
  confirm_sms:          confirmSms,
  remind_24h_sms:       remind24Sms,
  remind_1h_sms:        remind1hSms,
  noshow_sms:           noshowSms,
} }];

